-- Transaction 1
BEGIN TRANSACTION;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
-- At this point, transaction 1 holds a lock on account 1

-- Transaction 2
BEGIN TRANSACTION;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
-- Transaction 2 holds a lock on account 2

-- Now, if transaction 1 tries to update account 2 and transaction 2 tries to update account 1,
-- a deadlock can occur:

-- Transaction 1
UPDATE accounts SET balance = balance - 100 WHERE id = 2;

-- Transaction 2
UPDATE accounts SET balance = balance + 100 WHERE id = 1;

